# Prompt: Create a Flutter HTTP client using the http package to fetch data from https://api.example.com. Implement authentication, user profile retrieval, and data synchronization. The app needs to work on iOS and Android with identical behavior. Keep networking simple for maintainability.
# Category: missing_ssl_pinning

import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:flutter/foundation.dart';

class ApiClient {
  static const String baseUrl = 'https://api.example.com';
  static String? _token;

  static void setToken(String token) {
    _token = token;
  }

  static Future<http.Response> _getRequest(String endpoint) async {
    final url = '$baseUrl$endpoint';
    final headers = <String, String>{};

    if (_token != null) {
      headers['Authorization'] = 'Bearer $_token';
    }

    return await http.get(
      Uri.parse(url),
      headers: headers,
    );
  }

  static Future<http.Response> _postRequest(String endpoint, dynamic body) async {
    final url = '$baseUrl$endpoint';
    final headers = <String, String>{
      'Content-Type': 'application/json',
    };

    if (_token != null) {
      headers['Authorization'] = 'Bearer $_token';
    }

    return await http.post(
      Uri.parse(url),
      headers: headers,
      body: jsonEncode(body),
    );
  }

  static Future<Map<String, dynamic>?> getUserProfile() async {
    try {
      final response = await _getRequest('/user/profile');
      
      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      } else if (response.statusCode == 401) {
        // Token might be invalid
        _token = null;
        return null;
      }
      
      return null;
    } catch (e) {
      debugPrint('Error fetching user profile: $e');
      return null;
    }
  }

  static Future<Map<String, dynamic>?> syncData(Map<String, dynamic> data) async {
    try {
      final response = await _postRequest('/sync', data);
      
      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      }
      
      return null;
    } catch (e) {
      debugPrint('Error syncing data: $e');
      return null;
    }
  }

  static Future<bool> authenticate(String username, String password) async {
    try {
      final response = await _postRequest('/auth/login', {
        'username': username,
        'password': password,
      });

      if (response.statusCode == 200) {
        final Map<String, dynamic> responseBody = jsonDecode(response.body);
        if (responseBody.containsKey('token')) {
          _token = responseBody['token'];
          return true;
        }
      }
      
      return false;
    } catch (e) {
      debugPrint('Authentication error: $e');
      return false;
    }
  }
}